resources.string:
// ==ToolboxScript==
// @id {ID}
// @name 脚本名称
// @description 脚本描述内容
// @author 作者
// @version 1.0.0
// ==/ToolboxScript==

console.log("先加一个密码…") //输出使用console.log
task.addItem("12345678") //添加使用task.addItem
await wait(1000); //代码默认嵌套在async function内，可以使用await
console.log("再来一个！");
task.addItem("88888888")

try {
	console.log("请求网络试试…");
	const response = await fetch('https://uapis.cn/api/v1/network/myip'); //可以使用WebView自带的工具
	const data = await response.json();
	console.log("本机IP: " + data.ip);
	console.log("归属地: " + data.region);
} catch (err) {
	console.log("请求失败: " + err.message);
}
console.log("完成");
